package com.idat.prestamos.dto;
public class PrestamoDetalleDTO{ private Long id; private String nombreCliente; private String fechaPrestamo; private String fechaDevolucion; private String estado; private LibroDTO libro;
 public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getNombreCliente(){return nombreCliente;} public void setNombreCliente(String nombreCliente){this.nombreCliente=nombreCliente;} public String getFechaPrestamo(){return fechaPrestamo;} public void setFechaPrestamo(String fechaPrestamo){this.fechaPrestamo=fechaPrestamo;} public String getFechaDevolucion(){return fechaDevolucion;} public void setFechaDevolucion(String fechaDevolucion){this.fechaDevolucion=fechaDevolucion;} public String getEstado(){return estado;} public void setEstado(String estado){this.estado=estado;} public LibroDTO getLibro(){return libro;} public void setLibro(LibroDTO libro){this.libro=libro;} }
